class VersionChecker {
  static checkNodeVersion() {
    const currentVersion = process.version;
    Logger.info(`Node.js version: ${currentVersion}`);

    const required = CONFIG.requiredNodeVersion.replace(">=", "");
    const current = currentVersion.replace("v", "");

    if (this.compareVersions(current, required) < 0) {
      Logger.error(
        `Node.js ${CONFIG.requiredNodeVersion} is required. Current: ${currentVersion}`
      );
      return false;
    }
    return true;
  }

  static checkNpmVersion() {
    const npmVersion = runCommand("npm --version", { silent: true });
    if (!npmVersion) {
      Logger.error("npm is not installed or not accessible");
      return false;
    }

    const current = npmVersion.trim();
    const required = CONFIG.requiredNpmVersion.replace(">=", "");
    Logger.info(`npm version: ${current}`);

    if (this.compareVersions(current, required) < 0) {
      Logger.error(
        `npm ${CONFIG.requiredNpmVersion} is required. Current: ${current}`
      );
      return false;
    }
    return true;
  }

  static compareVersions(a, b) {
    const partsA = a.split(".").map(Number);
    const partsB = b.split(".").map(Number);

    for (let i = 0; i < Math.max(partsA.length, partsB.length); i++) {
      const numA = partsA[i] || 0;
      const numB = partsB[i] || 0;
      if (numA > numB) return 1;
      if (numA < numB) return -1;
    }
    return 0;
  }

  static runAllChecks() {
    Logger.section("Environment Checks");
    const nodeOk = this.checkNodeVersion();
    const npmOk = this.checkNpmVersion();

    if (!nodeOk || !npmOk) {
      Logger.error("Environment checks failed. Please update your tools.");
      return false;
    }

    Logger.success("All environment checks passed.");
    return true;
  }
}

