class LockFileGenerator {
  static generate(options = {}) {
    Logger.section("Generating package-lock.json");

    // Verify package.json exists
    if (!fs.existsSync(CONFIG.packageFileName)) {
      Logger.error("package.json not found in current directory");
      return false;
    }

    const packageJson = readJsonFile(CONFIG.packageFileName);
    Logger.info(`Project: ${packageJson.name}@${packageJson.version}`);

    // Remove existing lock file if clean generation requested
    if (options.clean && fs.existsSync(CONFIG.lockFileName)) {
      Logger.info("Removing existing package-lock.json for clean generation");
      fs.unlinkSync(CONFIG.lockFileName);
    }

    // Remove node_modules if clean generation requested
    if (options.clean && fs.existsSync("node_modules")) {
      Logger.info("Removing node_modules for clean generation");
      fs.rmSync("node_modules", { recursive: true, force: true });
    }

    // Generate lock file
    Logger.info("Running npm install to generate lock file...");
    const result = runCommand("npm install --package-lock-only", {
      silent: false,
    });

    if (result === null) {
      Logger.error("Failed to generate package-lock.json");
      return false;
    }

    // Verify the generated lock file
    if (!fs.existsSync(CONFIG.lockFileName)) {
      Logger.error("package-lock.json was not created");
      return false;
    }

    const lockFile = readJsonFile(CONFIG.lockFileName);
    Logger.success(
      `package-lock.json generated successfully (lockfileVersion: ${lockFile.lockfileVersion})`
    );

    // Calculate and display hash
    const hash = calculateFileHash(CONFIG.lockFileName);
    Logger.info(`Lock file SHA-256: ${hash}`);

    return true;
  }

  static generateForCI() {
    Logger.section("CI Lock File Generation");

    Logger.info("Using npm ci for deterministic installation...");
    const result = runCommand("npm ci", { silent: false });

    if (result === null) {
      Logger.error("npm ci failed - lock file may be out of sync");
      return false;
    }

    Logger.success("CI installation completed successfully");
    return true;
  }
}

