class LockFileValidator {
  static validate() {
    Logger.section("Validating package-lock.json");

    const results = {
      exists: false,
      parseable: false,
      versionMatch: false,
      lockfileVersion: null,
      integrityPresent: false,
      registryConsistent: false,
      noGitDependencies: true,
      noFileDependencies: true,
      synced: false,
      issues: [],
      warnings: [],
    };

    // Check existence
    if (!fs.existsSync(CONFIG.lockFileName)) {
      results.issues.push("package-lock.json does not exist");
      this.printResults(results);
      return results;
    }
    results.exists = true;

    // Check parseability
    const lockFile = readJsonFile(CONFIG.lockFileName);
    if (!lockFile) {
      results.issues.push("package-lock.json is not valid JSON");
      this.printResults(results);
      return results;
    }
    results.parseable = true;

    // Check lockfile version
    results.lockfileVersion = lockFile.lockfileVersion;
    if (lockFile.lockfileVersion < 2) {
      results.warnings.push(
        `lockfileVersion ${lockFile.lockfileVersion} is outdated. Consider upgrading to v2 or v3.`
      );
    }

    // Check version match with package.json
    const packageJson = readJsonFile(CONFIG.packageFileName);
    if (packageJson) {
      if (lockFile.version === packageJson.version) {
        results.versionMatch = true;
      } else {
        results.warnings.push(
          `Version mismatch: package.json (${packageJson.version}) vs lock file (${lockFile.version})`
        );
      }

      if (lockFile.name !== packageJson.name) {
        results.issues.push(
          `Name mismatch: package.json (${packageJson.name}) vs lock file (${lockFile.name})`
        );
      }
    }

    // Check integrity hashes
    results.integrityPresent = this.checkIntegrity(lockFile);

    // Check registry consistency
    results.registryConsistent = this.checkRegistries(lockFile, results);

    // Check for git and file dependencies
    this.checkDependencyTypes(lockFile, results);

    // Check sync status
    results.synced = this.checkSync();

    this.printResults(results);
    return results;
  }

  static checkIntegrity(lockFile) {
    let hasIntegrity = true;
    const packages = lockFile.packages || {};

    for (const [name, info] of Object.entries(packages)) {
      if (name === "") continue; // Skip root package
      if (!info.integrity && !info.link) {
        hasIntegrity = false;
        break;
      }
    }

    return hasIntegrity;
  }

  static checkRegistries(lockFile, results) {
    let consistent = true;
    const packages = lockFile.packages || {};

    for (const [name, info] of Object.entries(packages)) {
      if (name === "" || !info.resolved) continue;

      const isAllowed = CONFIG.allowedRegistries.some((registry) =>
        info.resolved.startsWith(registry)
      );

      if (!isAllowed) {
        consistent = false;
        results.warnings.push(
          `Package "${name}" resolved from non-standard registry: ${info.resolved}`
        );
      }
    }

    return consistent;
  }

  static checkDependencyTypes(lockFile, results) {
    const packages = lockFile.packages || {};

    for (const [name, info] of Object.entries(packages)) {
      if (name === "") continue;

      if (info.resolved && info.resolved.startsWith("git+")) {
        results.noGitDependencies = false;
        results.warnings.push(`Git dependency found: ${name}`);
      }

      if (info.resolved && info.resolved.startsWith("file:")) {
        results.noFileDependencies = false;
        results.warnings.push(`File dependency found: ${name}`);
      }
    }
  }

  static checkSync() {
    const result = runCommand("npm ls --json 2>/dev/null", {
      silent: true,
      ignoreError: true,
    });

    if (!result) return false;

    try {
      const tree = JSON.parse(result);
      return !tree.problems || tree.problems.length === 0;
    } catch {
      return false;
    }
  }

  static printResults(results) {
    Logger.info("Validation Results:");
    console.log("");

    const checks = [
      ["Lock file exists", results.exists],
      ["Valid JSON", results.parseable],
      ["Version match", results.versionMatch],
      ["Integrity hashes present", results.integrityPresent],
      ["Registry consistency", results.registryConsistent],
      ["No git dependencies", results.noGitDependencies],
      ["No file dependencies", results.noFileDependencies],
      ["Synced with package.json", results.synced],
    ];

    for (const [label, passed] of checks) {
      const icon = passed ? "\x1b[32m✓\x1b[0m" : "\x1b[31m✗\x1b[0m";
      console.log(`  ${icon} ${label}`);
    }

    if (results.lockfileVersion) {
      console.log(`\n  Lockfile version: ${results.lockfileVersion}`);
    }

    if (results.warnings.length > 0) {
      console.log("\n  Warnings:");
      results.warnings.forEach((w) => console.log(`    ⚠ ${w}`));
    }

    if (results.issues.length > 0) {
      console.log("\n  Issues:");
      results.issues.forEach((i) => console.log(`    ✗ ${i}`));
    }

    console.log("");

    const allPassed =
      results.exists &&
      results.parseable &&
      results.integrityPresent &&
      results.issues.length === 0;

    if (allPassed) {
      Logger.success("Lock file validation passed");
    } else {
      Logger.error("Lock file validation failed");
    }
  }
}

