class IntegrityVerifier {
  static verify() {
    Logger.section("Verifying Package Integrity");

    const lockFile = readJsonFile(CONFIG.lockFileName);
    if (!lockFile) {
      Logger.error("Cannot read package-lock.json");
      return false;
    }

    const packages = lockFile.packages || {};
    let totalPackages = 0;
    let withIntegrity = 0;
    let withoutIntegrity = 0;
    const missingIntegrity = [];

    for (const [name, info] of Object.entries(packages)) {
      if (name === "" || info.link) continue;
      totalPackages++;

      if (info.integrity) {
        withIntegrity++;

        // Validate integrity hash format
        if (!this.isValidIntegrityHash(info.integrity)) {
          Logger.warn(`Invalid integrity hash format for: ${name}`);
        }
      } else {
        withoutIntegrity++;
        missingIntegrity.push(name);
      }
    }

    Logger.info(`Total packages: ${totalPackages}`);
    Logger.info(`With integrity: ${withIntegrity}`);
    Logger.info(`Without integrity: ${withoutIntegrity}`);

    if (missingIntegrity.length > 0) {
      Logger.warn("Packages missing integrity hashes:");
      missingIntegrity.forEach((pkg) => console.log(`  - ${pkg}`));
    }

    // Verify installed packages match lock file
    Logger.info("\nVerifying installed packages against lock file...");
    const verifyResult = this.verifyInstalledPackages(lockFile);

    if (verifyResult.allMatch) {
      Logger.success("All installed packages match lock file integrity");
    } else {
      Logger.error("Some packages do not match lock file integrity");
      verifyResult.mismatches.forEach((m) => {
        Logger.error(`  Mismatch: ${m.package} - ${m.reason}`);
      });
    }

    return withoutIntegrity === 0 && verifyResult.allMatch;
  }

  static isValidIntegrityHash(hash) {
    // SRI hash format: algorithm-base64hash
    const sriPattern = /^(sha256|sha384|sha512)-[A-Za-z0-9+/]+=*$/;
    return sriPattern.test(hash);
  }

  static verifyInstalledPackages(lockFile) {
    const result = { allMatch: true, mismatches: [] };

    if (!fs.existsSync("node_modules")) {
      Logger.warn("node_modules not found - skipping installed package verification");
      return result;
    }

    const packages = lockFile.packages || {};

    for (const [name, info] of Object.entries(packages)) {
      if (name === "" || info.link || !info.integrity) continue;

      // Extract the actual package path from the lock file key
      const packagePath = path.join(name);
      const packageJsonPath = path.join(packagePath, "package.json");

      if (!fs.existsSync(packageJsonPath)) continue;

      const installedPkg = readJsonFile(packageJsonPath);
      if (!installedPkg) continue;

      if (info.version && installedPkg.version !== info.version) {
        result.allMatch = false;
        result.mismatches.push({
          package: name,
          reason: `Version mismatch: expected ${info.version}, found ${installedPkg.version}`,
        });
      }
    }

    return result;
  }

  static generateIntegrityReport() {
    Logger.section("Integrity Report");

    const lockFile = readJsonFile(CONFIG.lockFileName);
    if (!lockFile) {
      Logger.error("Cannot read package-lock.json");
      return null;
    }

    const report = {
      timestamp: new Date().toISOString(),
      lockfileHash: calculateFileHash(CONFIG.lockFileName),
      lockfileVersion: lockFile.lockfileVersion,
      algorithms: {},
      packages: {},
    };

    const packages = lockFile.packages || {};

    for (const [name, info] of Object.entries(packages)) {
      if (name === "" || info.link) continue;

      if (info.integrity) {
        const algorithm = info.integrity.split("-")[0];
        report.algorithms[algorithm] = (report.algorithms[algorithm] || 0) + 1;
      }

      report.packages[name] = {
        version: info.version,
        integrity: info.integrity || "MISSING",
        resolved: info.resolved || "N/A",
      };
    }

    // Save report
    ensureDir(CONFIG.reportDir);
    const reportPath = path.join(
      CONFIG.reportDir,
      `integrity-report-${getTimestamp()}.json`
    );
    writeJsonFile(reportPath, report);
    Logger.success(`Integrity report saved to: ${reportPath}`);

    return report;
  }
}

