class DependencyAuditor {
  static audit() {
    Logger.section("Security Audit");

    Logger.info("Running npm audit...");
    const result = runCommand("npm audit --json 2>/dev/null", {
      silent: true,
      ignoreError: true,
    });

    if (!result) {
      Logger.warn("npm audit returned no results or failed");
      return null;
    }

    try {
      const auditData = JSON.parse(result);
      this.printAuditSummary(auditData);
      return auditData;
    } catch {
      Logger.warn("Could not parse audit results");
      // Fall back to non-JSON audit
      runCommand("npm audit", { ignoreError: true });
      return null;
    }
  }

  static printAuditSummary(auditData) {
    if (auditData.metadata) {
      const meta = auditData.metadata;
      console.log("\n  Audit Summary:");
      console.log(`    Total dependencies: ${meta.totalDependencies || "N/A"}`);

      if (meta.vulnerabilities) {
        const vuln = meta.vulnerabilities;
        console.log("    Vulnerabilities:");
        console.log(`      Critical: ${vuln.critical || 0}`);
        console.log(`      High:     ${vuln.high || 0}`);
        console.log(`      Moderate: ${vuln.moderate || 0}`);
        console.log(`      Low:      ${vuln.low || 0}`);
        console.log(`      Info:     ${vuln.info || 0}`);

        const total =
          (vuln.critical || 0) +
          (vuln.high || 0) +
          (vuln.moderate || 0) +
          (vuln.low || 0);

        if (total === 0) {
          Logger.success("No vulnerabilities found");
        } else {
          Logger.warn(`Found ${total} vulnerabilities`);
        }
      }
    }

    // Save audit report
    ensureDir(CONFIG.reportDir);
    const reportPath = path.join(
      CONFIG.reportDir,
      `audit-report-${getTimestamp()}.json`
    );
    writeJsonFile(reportPath, auditData);
    Logger.info(`Audit report saved to: ${reportPath}`);
  }

  static fix() {
    Logger.section("Auto-fixing Vulnerabilities");

    Logger.info("Running npm audit fix...");
    runCommand("npm audit fix");

    Logger.info("\nRe-running audit to check remaining issues...");
    this.audit();
  }
}

