class LockFileSync {
  static sync() {
    Logger.section("Syncing package-lock.json with package.json");

    const packageJson = readJsonFile(CONFIG.packageFileName);
    const lockFile = readJsonFile(CONFIG.lockFileName);

    if (!packageJson) {
      Logger.error("Cannot read package.json");
      return false;
    }

    if (!lockFile) {
      Logger.warn("No existing lock file found. Generating new one...");
      return LockFileGenerator.generate();
    }

    // Compare dependencies
    const packageDeps = {
      ...packageJson.dependencies,
      ...packageJson.devDependencies,
    };

    const lockDeps = this.extractLockDependencies(lockFile);

    const analysis = {
      added: [],
      removed: [],
      versionChanged: [],
    };

    // Check for new or changed dependencies
    for (const [name, version] of Object.entries(packageDeps)) {
      if (!lockDeps[name]) {
        analysis.added.push({ name, version });
      } else if (lockDeps[name].specifier !== version) {
        analysis.versionChanged.push({
          name,
          from: lockDeps[name].specifier,
          to: version,
        });
      }
    }

    // Check for removed dependencies
    for (const [name] of Object.entries(lockDeps)) {
      if (!packageDeps[name]) {
        analysis.removed.push(name);
      }
    }

    // Print analysis
    if (analysis.added.length > 0) {
      Logger.info("New dependencies:");
      analysis.added.forEach((d) => console.log(`  + ${d.name}@${d.version}`));
    }

    if (analysis.removed.length > 0) {
      Logger.info("Removed dependencies:");
      analysis.removed.forEach((d) => console.log(`  - ${d}`));
    }

    if (analysis.versionChanged.length > 0) {
      Logger.info("Changed versions:");
      analysis.versionChanged.forEach((d) =>
        console.log(`  ~ ${d.name}: ${d.from} → ${d.to}`)
      );
    }

    const hasChanges =
      analysis.added.length > 0 ||
      analysis.removed.length > 0 ||
      analysis.versionChanged.length > 0;

    if (!hasChanges) {
      Logger.success("package-lock.json is already in sync");
      return true;
    }

    // Regenerate lock file
    Logger.info("\nRegenerating lock file to sync changes...");
    runCommand("npm install --package-lock-only");

    Logger.success("package-lock.json synced successfully");
    return true;
  }

  static extractLockDependencies(lockFile) {
    const deps = {};
    const packages = lockFile.packages || {};

    for (const [key, info] of Object.entries(packages)) {
      if (key === "") continue;

      // Extract package name from the key (e.g., "node_modules/express")
      const name = key.replace(/^node_modules\//, "");
      if (name.includes("node_modules/")) continue; // Skip nested deps

      deps[name] = {
        version: info.version,
        specifier: info.version, // Simplified
      };
    }

    return deps;
  }
}

