class SnapshotManager {
  static freeze() {
    Logger.section("Creating Lock File Snapshot");

    if (!fs.existsSync(CONFIG.lockFileName)) {
      Logger.error("No package-lock.json to snapshot");
      return false;
    }

    ensureDir(CONFIG.snapshotDir);

    const timestamp = getTimestamp();
    const hash = calculateFileHash(CONFIG.lockFileName);
    const snapshotName = `lock-snapshot-${timestamp}.json`;
    const snapshotPath = path.join(CONFIG.snapshotDir, snapshotName);

    // Create snapshot with metadata
    const lockContent = readJsonFile(CONFIG.lockFileName);
    const packageJson = readJsonFile(CONFIG.packageFileName);

    const snapshot = {
      metadata: {
        createdAt: new Date().toISOString(),
        hash: hash,
        nodeVersion: process.version,
        npmVersion: runCommand("npm --version", { silent: true })?.trim(),
        projectName: packageJson?.name,
        projectVersion: packageJson?.version,
      },
      lockFile: lockContent,
    };

    writeJsonFile(snapshotPath, snapshot);

    // Also create a simple copy
    const copyPath = path.join(
      CONFIG.snapshotDir,
      `package-lock-${timestamp}.json`
    );
    fs.copyFileSync(CONFIG.lockFileName, copyPath);

    Logger.success(`Snapshot created: ${snapshotPath}`);
    Logger.info(`Lock file copy: ${copyPath}`);
    Logger.info(`SHA-256: ${hash}`);

    // Update manifest
    this.updateManifest(snapshotName, hash, timestamp);

    return true;
  }

  static updateManifest(snapshotName, hash, timestamp) {
    const manifestPath = path.join(CONFIG.snapshotDir, "manifest.json");
    let manifest = readJsonFile(manifestPath) || { snapshots: [] };

    manifest.snapshots.push({
      name: snapshotName,
      hash: hash,
      timestamp: timestamp,
      createdAt: new Date().toISOString(),
    });

    writeJsonFile(manifestPath, manifest);
  }

  static listSnapshots() {
    Logger.section("Lock File Snapshots");

    const manifestPath = path.join(CONFIG.snapshotDir, "manifest.json");
    const manifest = readJsonFile(manifestPath);

    if (!manifest || manifest.snapshots.length === 0) {
      Logger.info("No snapshots found");
      return;
    }

    console.log("  Available snapshots:\n");
    manifest.snapshots.forEach((s, i) => {
      console.log(`  ${i + 1}. ${s.name}`);
      console.log(`     Hash: ${s.hash}`);
      console.log(`     Created: ${s.createdAt}\n`);
    });
  }

  static restore(snapshotIndex) {
    const manifestPath = path.join(CONFIG.snapshotDir, "manifest.json");
    const manifest = readJsonFile(manifestPath);

    if (!manifest || !manifest.snapshots[snapshotIndex]) {
      Logger.error("Snapshot not found");
      return false;
    }

    const snapshot = manifest.snapshots[snapshotIndex];
    const snapshotPath = path.join(CONFIG.snapshotDir, snapshot.name);
    const snapshotData = readJsonFile(snapshotPath);

    if (!snapshotData || !snapshotData.lockFile) {
      Logger.error("Cannot read snapshot data");
      return false;
    }

    // Backup current lock file
    if (fs.existsSync(CONFIG.lockFileName)) {
      const backupPath = `${CONFIG.lockFileName}.backup-${getTimestamp()}`;
      fs.copyFileSync(CONFIG.lockFileName, backupPath);
      Logger.info(`Current lock file backed up to: ${backupPath}`);
    }

    // Restore
    writeJsonFile(CONFIG.lockFileName, snapshotData.lockFile);
    Logger.success(`Restored lock file from snapshot: ${snapshot.name}`);

    return true;
  }
}

// ============================================================================
// Diff Tool
// ============================================================================

class LockFileDiff {
  static diff(file1Path, file2Path) {
    Logger.section("Lock File Diff");

    file1Path = file1Path || CONFIG.lockFileName;

    const lock1 = readJsonFile(file1Path);
    const lock2 = file2Path ? readJsonFile(file2Path) : null;

    if (!lock1) {
      Logger.error(`Cannot read: ${file1Path}`);
      return null;
    }

    if (file2Path && !lock2) {
      Logger.error(`Cannot read: ${file2Path}`);
      return null;
    }

    if (!lock2) {
      // Compare with last snapshot
      const manifestPath = path.join(CONFIG.snapshotDir, "manifest.json");
      const manifest = readJsonFile(manifestPath);

      if (!manifest || manifest.snapshots.length === 0) {
        Logger.error("No snapshot to compare against. Provide a second file.");
        return null;
      }

      const lastSnapshot = manifest.snapshots[manifest.snapshots.length - 1];
      const snapshotPath = path.join(CONFIG.snapshotDir, lastSnapshot.name);
      const snapshotData = readJsonFile(snapshotPath);

      if (!snapshotData || !snapshotData.lockFile) {
        Logger.error("Cannot read last snapshot");
        return null;
      }

      return this.compareLockFiles(snapshotData.lockFile, lock1, "snapshot", "current");
    }

    return this.compareLockFiles(lock1, lock2, file1Path, file2Path);
  }

  static compareLockFiles(lock1, lock2, label1, label2) {
    const packages1 = this.flattenPackages(lock1);
    const packages2 = this.flattenPackages(lock2);

    const allPackages = new Set([
      ...Object.keys(packages1),
      ...Object.keys(packages2),
    ]);

    const diff = {
      added: [],
      removed: [],
      updated: [],
      unchanged: 0,
    };

    for (const pkg of allPackages) {
      const in1 = packages1[pkg];
      const in2 = packages2[pkg];

      if (!in1 && in2) {
        diff.added.push({ name: pkg, version: in2.version });
      } else if (in1 && !in2) {
        diff.removed.push({ name: pkg, version: in1.version });
      } else if (in1.version !== in2.version) {
        diff.updated.push({
          name: pkg,
          from: in1.version,
          to: in2.version,
        });
      } else {
        diff.unchanged++;
      }
    }

    // Print diff
    console.log(`  Comparing: ${label1} ↔ ${label2}\n`);

    if (diff.added.length > 0) {
      console.log("  \x1b[32mAdded:\x1b[0m");
      diff.added.forEach((d) =>
        console.log(`    + ${d.name}@${d.version}`)
      );
      console.log("");
    }

    if (diff.removed.length > 0) {
      console.log("  \x1b[31mRemoved:\x1b[0m");
      diff.removed.forEach((d) =>
        console.log(`    - ${d.name}@${d.version}`)
      );
      console.log("");
    }

    if (diff.updated.length > 0) {
      console.log("  \x1b[33mUpdated:\x1b[0m");
      diff.updated.forEach((d) =>
        console.log(`    ~ ${d.name}: ${d.from} → ${d.to}`)
      );
      console.log("");
    }

    console.log(`  Unchanged: ${diff.unchanged} packages`);
    console.log(
      `  Total changes: ${diff.added.length + diff.removed.length + diff.updated.length}`
    );

    return diff;
  }

  static flattenPackages(lockFile) {
    const packages = {};
    const lockPackages = lockFile.packages || {};

    for (const [key, info] of Object.entries(lockPackages)) {
      if (key === "") continue;
      const name = key.replace(/^node_modules\//, "");
      packages[name] = {
        version: info.version,
        integrity: info.integrity,
      };
    }

    return packages;
  }
}

// ============================================================================
// CI Checker
// ============================================================================

class CIChecker {
  static check() {
    Logger.section("CI Readiness Check");

    const checks = [];

    // 1. Lock file exists
    checks.push({
      name: "Lock file exists",
      passed: fs.existsSync(CONFIG.lockFileName),
      critical: true,
    });

    // 2. Lock file is valid JSON
    const lockFile = readJsonFile(CONFIG.lockFileName);
    checks.push({
      name: "Lock file is valid JSON",
      passed: lockFile !== null,
      critical: true,
    });

    if (!lockFile) {
      this.printChecks(checks);
      return false;
    }

    // 3. Lock file version is modern
    checks.push({
      name: "Modern lockfile version (>=2)",
      passed: lockFile.lockfileVersion >= 2,
      critical: false,
    });

    // 4. No missing integrity hashes
    const integrityCheck = this.checkAllIntegrity(lockFile);
    checks.push({
      name: "All packages have integrity hashes",
      passed: integrityCheck,
      critical: CONFIG.ciStrictMode,
    });

    // 5. package.json exists
    checks.push({
      name: "package.json exists",
      passed: fs.existsSync(CONFIG.packageFileName),
      critical: true,
    });

    // 6. Names match
    const packageJson = readJsonFile(CONFIG.packageFileName);
    if (packageJson && lockFile) {
      checks.push({
        name: "Project name matches",
        passed: lockFile.name === packageJson.name,
        critical: true,
      });
    }

    // 7. .npmrc exists (optional but recommended)
    checks.push({
      name: ".npmrc configuration exists",
      passed: fs.existsSync(".npmrc"),
      critical: false,
    });

    // 8. No prepare scripts that might fail in CI
    if (packageJson && packageJson.scripts) {
      const hasPrepare = !!packageJson.scripts.prepare;
      checks.push({
        name: "No problematic prepare scripts",
        passed: !hasPrepare || this.isPrepareScriptSafe(packageJson.scripts.prepare),
        critical: false,
      });
    }

    // 9. npm ci dry run
    const ciDryRun = runCommand("npm ci --dry-run 2>&1", {
      silent: true,
      ignoreError: true,
    });
    checks.push({
      name: "npm ci dry run succeeds",
      passed: ciDryRun !== null,
      critical: true,
    });

    this.printChecks(checks);

    const criticalFailed = checks.some((c) => c.critical && !c.passed);
    return !criticalFailed;
  }

  static checkAllIntegrity(lockFile) {
    const packages = lockFile.packages || {};
    for (const [name, info] of Object.entries(packages)) {
      if (name === "" || info.link) continue;
      if (!info.integrity) return false;
    }
    return true;
  }

  static isPrepareScriptSafe(script) {
    const unsafePatterns = ["husky", "git", "pre-commit"];
    return !unsafePatterns.some((p) => script.toLowerCase().includes(p));
  }

  static printChecks(checks) {
    console.log("  CI Readiness Checks:\n");

    for (const check of checks) {
      const icon = check.passed ? "\x1b[32m✓\x1b[0m" : "\x1b[31m✗\x1b[0m";
      const severity = check.critical ? "(critical)" : "(recommended)";
      const severityColor = check.critical ? "\x1b[31m" : "\x1b[33m";

      console.log(
        `  ${icon} ${check.name} ${!check.passed ? `${severityColor}${severity}\x1b[0m` : ""}`
      );
    }

    const allPassed = checks.every((c) => c.passed);
    const criticalPassed = checks.filter((c) => c.critical).every((c) => c.passed);

    console.log("");

    if (allPassed) {
      Logger.success("All CI checks passed! Ready for deployment.");
    } else if (criticalPassed) {
      Logger.warn(
        "Critical checks passed, but some recommended checks failed."
      );
    } else {
      Logger.error("Critical CI checks failed. Fix issues before deploying.");
    }
  }
}

// ============================================================================
// Report Generator
// ============================================================================

class ReportGenerator {
  static generate() {
    Logger.section("Dependency Report");

    const lockFile = readJsonFile(CONFIG.lockFileName);
    const packageJson = readJsonFile(CONFIG.packageFileName);

    if (!lockFile || !packageJson) {
      Logger.error("Cannot read required files");
      return null;
    }

    const report = {
      project: {
        name: packageJson.name,
        version: packageJson.version,
        description: packageJson.description,
      },
      generated: new Date().toISOString(),
      lockfileVersion: lockFile.lockfileVersion,
      lockfileHash: calculateFileHash(CONFIG.lockFileName),
      summary: {
        totalDependencies: 0,
        directDependencies: Object.keys(packageJson.dependencies || {}).length,
        devDependencies: Object.keys(packageJson.devDependencies || {}).length,
        transitiveDependencies: 0,
      },
      dependencies: {
        direct: {},
        dev: {},
      },
      statistics: {
        registries: {},
        integrityAlgorithms: {},
        duplicatePackages: [],
      },
    };

    // Analyze packages
    const packages = lockFile.packages || {};
    const directDeps = new Set(
      Object.keys(packageJson.dependencies || {})
    );
    const devDeps = new Set(
      Object.keys(packageJson.devDependencies || {})
    );

    for (const [key, info] of Object.entries(packages)) {
      if (key === "") continue;

      report.summary.totalDependencies++;

      const name = key.replace(/^node_modules\//, "");

      // Categorize
      if (directDeps.has(name)) {
        report.dependencies.direct[name] = {
          version: info.version,
          resolved: info.resolved,
          integrity: info.integrity ? "present" : "missing",
        };
      } else if (devDeps.has(name)) {
        report.dependencies.dev[name] = {
          version: info.version,
          resolved: info.resolved,
          integrity: info.integrity ? "present" : "missing",
        };
      }

      // Registry stats
      if (info.resolved) {
        try {
          const url = new URL(info.resolved);
          const registry = `${url.protocol}//${url.host}`;
          report.statistics.registries[registry] =
            (report.statistics.registries[registry] || 0) + 1;
        } catch {
          // Not a valid URL
        }
      }

      // Integrity algorithm stats
      if (info.integrity) {
        const algo = info.integrity.split("-")[0];
        report.statistics.integrityAlgorithms[algo] =
          (report.statistics.integrityAlgorithms[algo] || 0) + 1;
      }
    }

    report.summary.transitiveDependencies =
      report.summary.totalDependencies -
      report.summary.directDependencies -
      report.summary.devDependencies;

    // Print summary
    console.log(`  Project: ${report.project.name}@${report.project.version}`);
    console.log(`  Lock file version: ${report.lockfileVersion}`);
    console.log(`  Lock file hash: ${report.lockfileHash}`);
    console.log("");
    console.log("  Dependencies:");
    console.log(`    Direct:     ${report.summary.directDependencies}`);
    console.log(`    Dev:        ${report.summary.devDependencies}`);
    console.log(`    Transitive: ${report.summary.transitiveDependencies}`);
    console.log(`    Total:      ${report.summary.totalDependencies}`);
    console.log("");
    console.log("  Registries:");
    for (const [registry, count] of Object.entries(
      report.statistics.registries
    )) {
      console.log(`    ${registry}: ${count} packages`);
    }
    console.log("");
    console.log("  Integrity Algorithms:");
    for (const [algo, count] of Object.entries(
      report.statistics.integrityAlgorithms
    )) {
      console.log(`    ${algo}: ${count} packages`);
    }

    // Save report
    ensureDir(CONFIG.reportDir);
    const reportPath = path.join(
      CONFIG.reportDir,
      `dependency-report-${getTimestamp()}.json`
    );
    writeJsonFile(reportPath, report);
    Logger.success(`\nReport saved to: ${reportPath}`);

    return report;
  }
}

