// ============================================================================
// Main CLI
// ============================================================================

class CLI {
  static run() {
    const args = process.argv.slice(2);
    const command = args[0] || "help";

    switch (command) {
      case "generate":
        VersionChecker.runAllChecks();
        LockFileGenerator.generate({ clean: false });
        break;

      case "clean":
        VersionChecker.runAllChecks();
        LockFileGenerator.generate({ clean: true });
        break;

      case "validate":
        LockFileValidator.validate();
        break;

      case "integrity":
        IntegrityVerifier.verify();
        IntegrityVerifier.generateIntegrityReport();
        break;

      case "audit":
        DependencyAuditor.audit();
        break;

      case "audit-fix":
        DependencyAuditor.fix();
        break;

      case "sync":
        LockFileSync.sync();
        break;

      case "freeze":
      case "snapshot":
        SnapshotManager.freeze();
        break;

      case "snapshots":
      case "list-snapshots":
        SnapshotManager.listSnapshots();
        break;

      case "restore":
        const index = parseInt(args[1]) - 1;
        if (isNaN(index)) {
          Logger.error("Please provide a snapshot number. Use 'snapshots' to list.");
        } else {
          SnapshotManager.restore(index);
        }
        break;

      case "diff":
        LockFileDiff.diff(args[1], args[2]);
        break;

      case "ci-check":
        const passed = CIChecker.check();
        process.exitCode = passed ? 0 : 1;
        break;

      case "report":
        ReportGenerator.generate();
        break;

      case "docs":
        DocumentationGenerator.generate();
        break;

      case "npmrc":
        NpmrcGenerator.generate();
        break;

      case "full-check":
        VersionChecker.runAllChecks();
        LockFileValidator.validate();
        IntegrityVerifier.verify();
        CIChecker.check();
        DependencyAuditor.audit();
        ReportGenerator.generate();
        break;

      case "help":
      default:
        this.printHelp();
        break;
    }
  }

  static printHelp() {
    console.log(`
╔══════════════════════════════════════════════════════════╗
║           Package Lock Manager v1.0.0                    ║
║   Manage package-lock.json for reproducible builds       ║
╚══════════════════════════════════════════════════════════╝

Usage: node package-lock-manager.js <command> [options]

Commands:

  Generation & Installation:
    generate          Generate/update package-lock.json
    clean             Clean regenerate (removes node_modules & lock file)

  Validation & Verification:
    validate          Validate lock file structure and content
    integrity         Verify package integrity hashes
    ci-check          Check if lock file is CI/CD ready

  Dependency Management:
    sync              Sync lock file with package.json
    audit             Run security audit
    audit-fix         Auto-fix security vulnerabilities
    report            Generate comprehensive dependency report

  Snapshots:
    freeze            Create a snapshot of current lock file
    snapshots         List available snapshots
    restore <n>       Restore lock file from snapshot #n

  Comparison:
    diff [f1] [f2]    Compare two lock files (or current vs snapshot)

  Documentation:
    docs              Generate management guide (Markdown)
    npmrc             Generate recommended .npmrc file

  Comprehensive:
    full-check        Run all checks and generate reports

  help              Show this help message

Examples:
    node package-lock-manager.js generate
    node package-lock-manager.js ci-check
    node package-lock-manager.js freeze
    node package-lock-manager.js diff old-lock.json new-lock.json
    node package-lock-manager.js full-check
`);
  }
}

// ============================================================================
// Entry Point
